class Solution {
public:
    int countKReducibleNumbers(string s, int k) {
        int n = 0, res = 0;
        for (char c : s) {
            n = n * 2 + (c - '0');
        }
        for (int i = 1; i < n; i++) {
            int x = i, cnt = 0;
            while (x > 1) {
                x = __builtin_popcount(x);
                cnt++;
                if (cnt > k) break;
            }
            if (x == 1) res++;
        }
        return res % (1e9 + 7);
    }
};
```
